import json

def json_transformer(data, field_mapping: dict[str, str] | None = None, filter_fields: list[str] | None = None) -> dict:
    if isinstance(data, str):
        data = json.loads(data)
    result = data
    if field_mapping:
        if isinstance(result, list):
            result = [{field_mapping.get(k, k): v for k, v in item.items()} for item in result]
        elif isinstance(result, dict):
            result = {field_mapping.get(k, k): v for k, v in result.items()}
    if filter_fields:
        if isinstance(result, list):
            result = [{k: v for k, v in item.items() if k in filter_fields} for item in result]
        elif isinstance(result, dict):
            result = {k: v for k, v in result.items() if k in filter_fields}
    return {"transformed": result}
